/**
 * Translate an era string like "Modern (1788-1860)" to the target language.
 * Returns the original string if langCode is 'en' or no translation is found.
 * @param {string} era - Era string in format "Period Name (dates)"
 * @param {string} langCode - ISO language code (e.g. 'pt', 'ja')
 * @returns {string} Translated era string
 */
export function translateEra(era, langCode) {
  if (!langCode || langCode === 'en') return era;
  const match = era.match(/^(.+?)\s*\((.+)\)$/);
  if (!match) return era;
  const [, periodName, dates] = match;
  const translations = ERA_TRANSLATIONS[periodName.trim()];
  if (!translations || !translations[langCode]) return era;
  return `${translations[langCode]} (${dates})`;
}

/**
 * Translate a school string like "Logical Positivism / Analytic Philosophy".
 * Splits compound schools by " / ", translates each part, and rejoins.
 * Returns the original string if langCode is 'en' or no translation is found.
 * @param {string} school - School name (may contain " / " for compound schools)
 * @param {string} langCode - ISO language code (e.g. 'pt', 'ja')
 * @returns {string} Translated school string
 */
export function translateSchool(school, langCode) {
  if (!langCode || langCode === 'en') return school;
  const parts = school.split(' / ');
  const translated = parts.map((part) => {
    const t = SCHOOL_TRANSLATIONS[part.trim()];
    return (t && t[langCode]) || part;
  });
  return translated.join(' / ');
}
